// Set the date range for the last 7 days
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const since = Math.floor(sevenDaysAgo.getTime() / 1000);
const until = Math.floor(now.getTime() / 1000);

return [{
  json: {
    since,
    until,
    sinceISO: sevenDaysAgo.toISOString(),
    untilISO: now.toISOString(),
    reportDate: now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

// Normalize all data from Facebook, Instagram, and Google Reviews
const allItems = [];

// --- FACEBOOK ---
const fbData = $('Fetch Facebook Comments').all();
for (const item of fbData) {
  const post = item.json;
  // Post-level message
  if (post.message) {
    allItems.push({
      source: 'Facebook',
      type: 'post',
      text: post.message,
      timestamp: post.created_time || new Date().toISOString()
    });
  }
  // Comment-level messages
  if (post.comments && post.comments.data) {
    for (const comment of post.comments.data) {
      if (comment.message) {
        allItems.push({
          source: 'Facebook',
          type: 'comment',
          text: comment.message,
          author: comment.from ? comment.from.name : 'Unknown',
          timestamp: comment.created_time || new Date().toISOString()
        });
      }
    }
  }
}

// --- INSTAGRAM ---
const igData = $('Fetch Instagram Comments').all();
for (const item of igData) {
  const media = item.json;
  if (media.comments && media.comments.data) {
    for (const comment of media.comments.data) {
      if (comment.text) {
        allItems.push({
          source: 'Instagram',
          type: 'comment',
          text: comment.text,
          author: comment.username || 'Unknown',
          timestamp: comment.timestamp || new Date().toISOString()
        });
      }
    }
  }
}

// --- GOOGLE REVIEWS ---
const gData = $('Fetch Google Reviews').all();
for (const item of gData) {
  const reviewList = item.json.reviews || [];
  for (const review of reviewList) {
    const reviewDate = new Date(review.updateTime);
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    // Only include reviews from last 7 days
    if (reviewDate >= sevenDaysAgo) {
      allItems.push({
        source: 'Google',
        type: 'review',
        text: review.comment || '',
        author: review.reviewer ? review.reviewer.displayName : 'Anonymous',
        rating: review.starRating,
        timestamp: review.updateTime
      });
    }
  }
}

// --- FALLBACK: MOCK DATA for testing if all arrays are empty ---
if (allItems.length === 0) {
  const mockFeedback = [
    { source: 'Facebook', type: 'comment', text: 'The view at sunset was absolutely breathtaking! Loved every moment.', author: 'Maria Santos', timestamp: new Date().toISOString() },
    { source: 'Google', type: 'review', text: 'Great place but the WiFi signal was very weak. We could barely load a page.', author: 'John Cruz', rating: 'FOUR', timestamp: new Date().toISOString() },
    { source: 'Instagram', type: 'comment', text: 'Do you have a swimming pool? My kids would love it!', author: 'ana_travels', timestamp: new Date().toISOString() },
    { source: 'Facebook', type: 'comment', text: 'Staff was incredibly friendly and welcoming. They went above and beyond!', author: 'Robert Lim', timestamp: new Date().toISOString() },
    { source: 'Google', type: 'review', text: 'Rooms were clean but a bit overpriced for what you get. The nature view is nice though.', author: 'Carla Reyes', rating: 'THREE', timestamp: new Date().toISOString() },
    { source: 'Facebook', type: 'comment', text: 'The signal here is so weak, I had to go outside just to send a message. Please fix this!', author: 'Mike Torres', timestamp: new Date().toISOString() },
    { source: 'Instagram', type: 'comment', text: 'Is there a pool? We are planning to visit next month with our family.', author: 'jess_explorer', timestamp: new Date().toISOString() },
    { source: 'Google', type: 'review', text: 'We had a wonderful time! The nature trails are amazing and the staff is top notch.', author: 'Lisa Park', rating: 'FIVE', timestamp: new Date().toISOString() },
    { source: 'Facebook', type: 'comment', text: 'Weak internet connection throughout our entire stay. Very frustrating.', author: 'David Go', timestamp: new Date().toISOString() },
    { source: 'Instagram', type: 'comment', text: 'Do you offer a swimming pool for guests?', author: 'travel_ph', timestamp: new Date().toISOString() },
    { source: 'Google', type: 'review', text: 'Prices seem high but the experience is worth it. Sunset view is the #1 highlight!', author: 'Nina Flores', rating: 'FOUR', timestamp: new Date().toISOString() },
    { source: 'Facebook', type: 'comment', text: 'The sunset here is absolutely magical. Best resort experience we have had!', author: 'Chris Sy', timestamp: new Date().toISOString() }
  ];
  for (const m of mockFeedback) allItems.push(m);
}

return allItems.map(item => ({ json: item }));

// Aggregate all feedback items into a single batch for AI analysis
const allItems = $input.all();
const feedbackList = allItems.map((item, index) => ({
  id: index + 1,
  source: item.json.source,
  type: item.json.type,
  text: item.json.text,
  author: item.json.author || 'Guest',
  timestamp: item.json.timestamp
}));

return [{
  json: {
    totalFeedback: feedbackList.length,
    feedbackBatch: JSON.stringify(feedbackList),
    reportDate: $('Set Date Range').first().json.reportDate
  }
}];

values.content:
=Analyze the following guest feedback from the past 7 days for a nature resort.

FEEDBACK DATA:
{{$json.feedbackBatch}}

Perform a complete sentiment analysis and return a single JSON object with EXACTLY this structure:
{
  "summary": {
    "totalAnalyzed": <number>,
    "positiveCount": <number>,
    "neutralCount": <number>,
    "negativeCount": <number>,
    "positivePercent": <number 0-100>,
    "overallSentiment": "Positive|Neutral|Negative",
    "topKeyword": "<single most mentioned positive word>",
    "topAlert": "<single most mentioned complaint or concern>"
  },
  "categories": {
    "Price": { "mentions": <number>, "sentiment": "Positive|Neutral|Negative", "sample": "<example quote>" },
    "Facility": { "mentions": <number>, "sentiment": "Positive|Neutral|Negative", "sample": "<example quote>" },
    "Staff": { "mentions": <number>, "sentiment": "Positive|Neutral|Negative", "sample": "<example quote>" },
    "Nature": { "mentions": <number>, "sentiment": "Positive|Neutral|Negative", "sample": "<example quote>" }
  },
  "individualResults": [
    { "id": <number>, "sentiment": "Positive|Neutral|Negative", "category": "Price|Facility|Staff|Nature", "keyTheme": "<2-3 word theme>" }
  ],
  "trends": [
    { "theme": "<topic>", "count": <number>, "description": "<one sentence>", "isKnowledgeBaseLeak": <true|false> }
  ],
  "knowledgeBaseLeaks": [
    { "question": "<the FAQ question>", "frequency": <number>, "suggestedAnswer": "<draft answer for owner>" }
  ],
  "actionableInsights": [
    { "priority": "High|Medium|Low", "area": "<area>", "finding": "<what was found>", "recommendation": "<what owner should do>" }
  ],
  "execSummary": "<2-3 sentence executive summary for the resort owner, highlight wins, alerts, and top action>"
}

Rules:
- knowledgeBaseLeaks must ONLY include themes mentioned 3+ times
- isKnowledgeBaseLeak in trends = true if count >= 3
- Be specific and actionable
- Return ONLY the JSON object, nothing else

parameters.jsCode:
// Parse the AI response JSON
const rawContent = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';

let analysis;
try {
  // Strip any accidental markdown code fences
  const cleaned = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  // Fallback mock analysis if parse fails
  analysis = {
    summary: {
      totalAnalyzed: 12,
      positiveCount: 8,
      neutralCount: 2,
      negativeCount: 2,
      positivePercent: 67,
      overallSentiment: 'Positive',
      topKeyword: 'Sunset',
      topAlert: 'Weak WiFi Signal'
    },
    categories: {
      Price: { mentions: 3, sentiment: 'Neutral', sample: 'Prices seem high but worth it' },
      Facility: { mentions: 4, sentiment: 'Negative', sample: 'Weak signal throughout our stay' },
      Staff: { mentions: 3, sentiment: 'Positive', sample: 'Staff was incredibly friendly' },
      Nature: { mentions: 6, sentiment: 'Positive', sample: 'Sunset was breathtaking' }
    },
    individualResults: [],
    trends: [
      { theme: 'Weak WiFi / Signal', count: 3, description: '3 guests complained about weak internet connectivity', isKnowledgeBaseLeak: true },
      { theme: 'Swimming Pool Request', count: 3, description: '3 guests asked if there is a pool', isKnowledgeBaseLeak: true },
      { theme: 'Sunset Experience', count: 4, description: '4 guests praised the sunset view', isKnowledgeBaseLeak: false }
    ],
    knowledgeBaseLeaks: [
      { question: 'Is there a swimming pool?', frequency: 3, suggestedAnswer: 'We currently do not have a swimming pool, but we offer natural swimming spots nearby. We recommend bringing swimwear for the river.' },
      { question: 'How is the WiFi/signal here?', frequency: 3, suggestedAnswer: 'Our resort is set in a nature environment with limited signal. We recommend treating your stay as a digital detox. For emergencies, our front desk has a dedicated line.' }
    ],
    actionableInsights: [
      { priority: 'High', area: 'Facility', finding: '3 guests complained about weak WiFi signal', recommendation: 'Add a clear "Off-Grid Digital Detox" disclaimer to all booking pages and FAQs to set expectations.' },
      { priority: 'High', area: 'FAQ', finding: '3 guests asked about a swimming pool', recommendation: 'Add pool/swimming FAQ to booking page and Messenger auto-reply.' },
      { priority: 'Medium', area: 'Marketing', finding: 'Sunset is the top positive keyword with 4 mentions', recommendation: 'Feature sunset content more prominently in social media posts and reels.' }
    ],
    execSummary: 'This week showed strong overall positive sentiment driven by nature experiences and staff warmth. The primary alert is recurring WiFi complaints — an immediate FAQ/disclaimer update is recommended. Three guests independently asked about a pool, flagging it as a Knowledge Base gap to address.'
  };
}

const reportDate = $('Set Date Range').first().json.reportDate;
const summary = analysis.summary;

// Build the Telegram message
const sentimentEmoji = summary.positivePercent >= 70 ? '🟢' : summary.positivePercent >= 50 ? '🟡' : '🔴';

const leaks = analysis.knowledgeBaseLeaks || [];
const leakLines = leaks.length > 0
  ? leaks.map(l => `   • "${l.question}" (${l.frequency}x asked)`).join('\n')
  : '   • None this week ✅';

const insights = (analysis.actionableInsights || []).filter(i => i.priority === 'High');
const insightLines = insights.length > 0
  ? insights.map(i => `   🔺 [${i.area}] ${i.recommendation}`).join('\n')
  : '   • No critical actions this week.';

const categoryLines = Object.entries(analysis.categories || {}).map(([cat, data]) => {
  const emoji = data.sentiment === 'Positive' ? '😊' : data.sentiment === 'Negative' ? '😟' : '😐';
  return `   ${emoji} ${cat}: ${data.mentions} mention(s) — ${data.sentiment}`;
}).join('\n');

const trendLines = (analysis.trends || []).map(t => {
  const flag = t.isKnowledgeBaseLeak ? ' 🚩 KB Gap' : '';
  return `   • "${t.theme}" — ${t.count}x${flag}`;
}).join('\n');

const telegramMessage = `📊 *WEEKLY RESORT HEALTH REPORT*
📅 ${reportDate}
━━━━━━━━━━━━━━━━━━━━

${sentimentEmoji} *SENTIMENT SCORE: ${summary.positivePercent}% Positive*
   Total Feedback Analyzed: ${summary.totalAnalyzed}
   ✅ Positive: ${summary.positiveCount} | ⚠️ Neutral: ${summary.neutralCount} | ❌ Negative: ${summary.negativeCount}

🏷️ *TOP KEYWORD:* "${summary.topKeyword}"
🚨 *TOP ALERT:* "${summary.topAlert}"

📂 *CATEGORY BREAKDOWN:*
${categoryLines}

📈 *THIS WEEK'S TRENDS:*
${trendLines}

💡 *KNOWLEDGE BASE GAPS (3+ asks):*
${leakLines}

🎯 *HIGH-PRIORITY ACTIONS:*
${insightLines}

📝 *EXECUTIVE SUMMARY:*
_${analysis.execSummary}_

━━━━━━━━━━━━━━━━━━━━
✅ Full data logged to Google Sheets`;

return [{
  json: {
    analysis,
    telegramMessage,
    summary,
    reportDate
  }
}];

// Prepare rows for Google Sheets — one row per feedback item with full analysis
const parsed = $('Parse AI Analysis').first().json;
const analysis = parsed.analysis;
const summary = parsed.summary;
const reportDate = parsed.reportDate;

const rows = [];

// Row 1: Summary row for the weekly overview sheet
rows.push({
  json: {
    sheetType: 'SUMMARY',
    reportDate,
    totalAnalyzed: summary.totalAnalyzed,
    positiveCount: summary.positiveCount,
    neutralCount: summary.neutralCount,
    negativeCount: summary.negativeCount,
    positivePercent: summary.positivePercent,
    overallSentiment: summary.overallSentiment,
    topKeyword: summary.topKeyword,
    topAlert: summary.topAlert,
    execSummary: analysis.execSummary,
    pricesMentions: analysis.categories?.Price?.mentions || 0,
    facilityMentions: analysis.categories?.Facility?.mentions || 0,
    staffMentions: analysis.categories?.Staff?.mentions || 0,
    natureMentions: analysis.categories?.Nature?.mentions || 0,
    priceSentiment: analysis.categories?.Price?.sentiment || '',
    facilitySentiment: analysis.categories?.Facility?.sentiment || '',
    staffSentiment: analysis.categories?.Staff?.sentiment || '',
    natureSentiment: analysis.categories?.Nature?.sentiment || ''
  }
});

return rows;

// Prepare Knowledge Base Leak rows
const analysis = $('Parse AI Analysis').first().json.analysis;
const reportDate = $('Parse AI Analysis').first().json.reportDate;
const leaks = analysis.knowledgeBaseLeaks || [];

if (leaks.length === 0) {
  return [{ json: { noLeaks: true, reportDate } }];
}

return leaks.map(leak => ({
  json: {
    reportDate,
    question: leak.question,
    frequency: leak.frequency,
    suggestedAnswer: leak.suggestedAnswer,
    status: 'Pending Review'
  }
}));

// Prepare individual feedback rows for the detailed Feedback Log sheet
const analysis = $('Parse AI Analysis').first().json.analysis;
const reportDate = $('Parse AI Analysis').first().json.reportDate;
const allFeedback = $('Normalize & Merge All Feedback').all();
const individualResults = analysis.individualResults || [];

const rows = allFeedback.map((item, index) => {
  const result = individualResults.find(r => r.id === index + 1) || {};
  return {
    json: {
      reportDate,
      source: item.json.source,
      type: item.json.type,
      author: item.json.author || 'Guest',
      text: item.json.text,
      timestamp: item.json.timestamp,
      sentiment: result.sentiment || 'Neutral',
      category: result.category || 'Uncategorized',
      keyTheme: result.keyTheme || ''
    }
  };
});

return rows;
